package dev.langchain4j.model.googleai;

import java.util.List;

class GeminiStreamingCandidatesRepro {
    public static void main(String[] args) {
        boolean expectExceptions = args.length > 0 && args[0].equals("reproduce");
        runCase("null candidates", new GeminiGenerateContentResponse("id", "model", null, null, null), expectExceptions);
        runCase("empty candidates", new GeminiGenerateContentResponse("id", "model", List.of(), null, null), expectExceptions);
    }

    private static void runCase(String name, GeminiGenerateContentResponse response, boolean expectExceptions) {
        GeminiStreamingResponseBuilder builder = new GeminiStreamingResponseBuilder(false, false);
        try {
            GeminiStreamingResponseBuilder.TextAndTools result = builder.append(response);
            if (expectExceptions) {
                throw new AssertionError(name + " unexpectedly succeeded with " + result);
            }
            if (result.maybeText().isPresent() || result.maybeThought().isPresent() || !result.tools().isEmpty()) {
                throw new AssertionError(name + " should return empty TextAndTools but got " + result);
            }
            System.out.println(name + ": returned empty TextAndTools");
        } catch (NullPointerException | IndexOutOfBoundsException e) {
            if (!expectExceptions) {
                throw new AssertionError(name + " should not throw after fix", e);
            }
            System.out.println(name + ": reproduced " + e.getClass().getSimpleName());
        }
    }
}
